// src/App.js
import React, { useState, useEffect } from "react";
import {
  BrowserRouter,
  Routes,
  Route,
  Navigate,
  useNavigate,
} from "react-router-dom";

import { onAuthChange, logoutUser } from "./utils/firebase";

import Sidebar from "./components/Sidebar";
import Topbar  from "./components/Topbar";
import LandingPage   from "./pages/LandingPage";
import DashboardPage from "./pages/DashboardPage";
import PracticePage  from "./pages/PracticePage";
import ResultsPage   from "./pages/ResultsPage";
import ProgressPage  from "./pages/ProgressPage";
import LogoutPage    from "./pages/LogoutPage";

import "./App.css";

function AppShell({ user, onLogout }) {
  const navigate = useNavigate();
  const [analysisData, setAnalysisData] = useState(null);

  const legacyNavigate = (page, data = null) => {
    if (data) setAnalysisData(data);

    const routeMap = {
      landing:   "/",
      dashboard: "/dashboard",
      home:      "/dashboard",
      practice:  "/practice",
      scenarios: "/scenarios",
      results:   "/results",
      progress:  "/progress",
      settings:  "/settings",
      logout:    "/logout",
    };

    navigate(routeMap[page] ?? "/dashboard");
  };

  return (
    <div className="app-shell">
      {/* ── Persistent sidebar (authenticated only) ── */}
      {user && <Sidebar user={user} onLogout={() => navigate("/logout")} />}

      {/* ── Main content column ───────────────────── */}
      <div className={`app-content${user ? " with-sidebar" : ""}`}>

        {/* Shared Topbar — shown only when logged in */}
        {user && <Topbar user={user} />}

        {/* Scrollable page area */}
        <div className="app-page-area">
          <Routes>
            <Route
              path="/"
              element={
                user ? (
                  <Navigate to="/dashboard" replace />
                ) : (
                  <LandingPage navigate={legacyNavigate} />
                )
              }
            />

            <Route
              path="/dashboard"
              element={
                user ? (
                  <DashboardPage
                    navigate={legacyNavigate}
                    user={user}
                    onLogout={onLogout}
                  />
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/practice"
              element={
                user ? (
                  <PracticePage
                    navigate={legacyNavigate}
                    user={user}
                    onLogout={onLogout}
                  />
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/scenarios"
              element={
                user ? (
                  <PracticePage
                    navigate={legacyNavigate}
                    user={user}
                    onLogout={onLogout}
                  />
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/progress"
              element={
                user ? (
                  <ProgressPage
                    navigate={legacyNavigate}
                    user={user}
                    onLogout={onLogout}
                  />
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/settings"
              element={
                user ? (
                  <DashboardPage
                    navigate={legacyNavigate}
                    user={user}
                    onLogout={onLogout}
                  />
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/logout"
              element={
                user ? (
                  <LogoutPage
                    navigate={legacyNavigate}
                    onLogout={onLogout}
                  />
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="/results"
              element={
                user ? (
                  <ResultsPage
                    results={analysisData}
                    navigate={legacyNavigate}
                    user={user}
                    onLogout={onLogout}
                  />
                ) : (
                  <Navigate to="/" replace />
                )
              }
            />

            <Route
              path="*"
              element={<Navigate to={user ? "/dashboard" : "/"} replace />}
            />
          </Routes>
        </div>
      </div>
    </div>
  );
}

export default function App() {
  const [user, setUser] = useState(undefined);

  useEffect(() => {
    const unsub = onAuthChange((firebaseUser) => {
      setUser(firebaseUser);
    });
    return () => unsub();
  }, []);

  const handleLogout = async () => {
    await logoutUser();
    setUser(null);
  };

  if (user === undefined) {
    return (
      <div className="app-loading">
        <div className="spinner" />
      </div>
    );
  }

  return (
    <BrowserRouter>
      <AppShell user={user} onLogout={handleLogout} />
    </BrowserRouter>
  );
}
